import "../pages/styles/Navbar.css";
import { useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  // 🔐 Get role from localStorage
  const role = localStorage.getItem("role");

  const handleLogout = () => {
    localStorage.clear();   // clears role + login info
    navigate("/");          // go back to home
    window.location.reload(); // refresh navbar state
  };

  return (
    <nav className="navbar">
      <div className="logo" onClick={() => navigate("/")}>
        Book<span>Sphere</span>
      </div>

      <div className="nav-links">
        {/* Use navigate instead of <a> to avoid reload */}
        <span onClick={() => navigate("/")}>Archive</span>
        <span onClick={() => navigate("/books")}>The Library</span>

        {/* SHOW ONLY FOR STUDENT */}
        {role === "Student" && (
          <span onClick={() => navigate("/borrowed")}>My Books</span>
        )}

        {/* AUTH BUTTON */}
        {!role ? (
          <button className="enter-btn" onClick={() => navigate("/auth")}>
            Enter
          </button>
        ) : (
          <button className="enter-btn" onClick={handleLogout}>
            Logout
          </button>
        )}
      </div>
    </nav>
  );
}

export default Navbar;
